import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.PErH1-Uo.js";const u=JSON.parse('{"title":"02. Comandos de red Linux","description":"","frontmatter":{"title":"02. Comandos de red Linux","parent":"Linux"},"headers":[],"relativePath":"linux/linux/comandos_red_avanzados.md","filePath":"linux/linux/comandos_red_avanzados.md","lastUpdated":1775646765000}'),s={name:"linux/linux/comandos_red_avanzados.md"};function r(i,t,n,c,l,h){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="🌐-comandos-avanzados-de-administracion-de-red-en-linux" tabindex="-1">🌐 Comandos Avanzados de Administración de Red en Linux <a class="header-anchor" href="#🌐-comandos-avanzados-de-administracion-de-red-en-linux" aria-label="Permalink to &quot;🌐 Comandos Avanzados de Administración de Red en Linux&quot;">​</a></h1><h2 id="_1-configuracion-de-interfaces-de-red" tabindex="-1">1. <strong>Configuración de interfaces de red</strong> <a class="header-anchor" href="#_1-configuracion-de-interfaces-de-red" aria-label="Permalink to &quot;1. **Configuración de interfaces de red**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>ip a</code></td><td>Muestra interfaces y direcciones IP.</td><td><code>ip a</code></td></tr><tr><td><code>ip link set</code></td><td>Activa o desactiva una interfaz.</td><td><code>sudo ip link set eth0 up</code></td></tr><tr><td><code>ip addr add</code></td><td>Asigna una IP a una interfaz.</td><td><code>sudo ip addr add 192.168.1.50/24 dev eth0</code></td></tr><tr><td><code>ip route</code></td><td>Muestra o modifica rutas de red.</td><td><code>ip route show</code></td></tr><tr><td><code>ip route add</code></td><td>Añade una nueva ruta.</td><td><code>sudo ip route add 10.0.0.0/24 via 192.168.1.1</code></td></tr><tr><td><code>ethtool</code></td><td>Muestra y ajusta parámetros de una tarjeta de red.</td><td><code>sudo ethtool eth0</code></td></tr><tr><td><code>nmcli</code></td><td>Configura redes con <strong>NetworkManager</strong>.</td><td><code>nmcli device status</code></td></tr></tbody></table><hr><h2 id="_2-diagnostico-de-conectividad" tabindex="-1">2. <strong>Diagnóstico de conectividad</strong> <a class="header-anchor" href="#_2-diagnostico-de-conectividad" aria-label="Permalink to &quot;2. **Diagnóstico de conectividad**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>ping</code></td><td>Verifica la conectividad a un host.</td><td><code>ping 8.8.8.8</code></td></tr><tr><td><code>traceroute</code></td><td>Muestra la ruta que siguen los paquetes hasta el destino.</td><td><code>traceroute google.com</code></td></tr><tr><td><code>mtr</code></td><td>Combina <code>ping</code> y <code>traceroute</code> en tiempo real.</td><td><code>mtr 8.8.8.8</code></td></tr><tr><td><code>dig</code></td><td>Consulta información DNS.</td><td><code>dig google.com</code></td></tr><tr><td><code>nslookup</code></td><td>Alternativa a <code>dig</code> para consultas DNS.</td><td><code>nslookup openai.com</code></td></tr><tr><td><code>arp -n</code></td><td>Muestra la tabla ARP (IP ↔ MAC).</td><td><code>arp -n</code></td></tr><tr><td><code>tcpdump</code></td><td>Captura y analiza tráfico de red en tiempo real.</td><td><code>sudo tcpdump -i eth0 port 80</code></td></tr><tr><td><code>iftop</code></td><td>Muestra uso de ancho de banda en tiempo real.</td><td><code>sudo iftop</code></td></tr><tr><td><code>iperf3</code></td><td>Mide velocidad y rendimiento de la red.</td><td><code>iperf3 -c 192.168.1.10</code></td></tr></tbody></table><hr><h2 id="_3-monitoreo-de-puertos-y-servicios" tabindex="-1">3. <strong>Monitoreo de puertos y servicios</strong> <a class="header-anchor" href="#_3-monitoreo-de-puertos-y-servicios" aria-label="Permalink to &quot;3. **Monitoreo de puertos y servicios**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>ss -tulnp</code></td><td>Muestra puertos abiertos y procesos asociados.</td><td><code>sudo ss -tulnp</code></td></tr><tr><td><code>netstat -tulnp</code> <em>(obsoleto)</em></td><td>Versión clásica de <code>ss</code>.</td><td><code>sudo netstat -tulnp</code></td></tr><tr><td><code>lsof -i</code></td><td>Lista procesos que usan red y puertos.</td><td><code>sudo lsof -i :80</code></td></tr><tr><td><code>nmap</code></td><td>Escanea red o puertos abiertos.</td><td><code>nmap 192.168.1.0/24</code></td></tr><tr><td><code>watch</code></td><td>Monitorea comandos en tiempo real.</td><td><code>watch ss -tulnp</code></td></tr></tbody></table><hr><h2 id="_4-gestion-de-firewall-iptables-nftables" tabindex="-1">4. <strong>Gestión de Firewall (iptables/nftables)</strong> <a class="header-anchor" href="#_4-gestion-de-firewall-iptables-nftables" aria-label="Permalink to &quot;4. **Gestión de Firewall (iptables/nftables)**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>iptables -L -v</code></td><td>Lista reglas activas de firewall.</td><td><code>sudo iptables -L -v</code></td></tr><tr><td><code>iptables -A INPUT</code></td><td>Añade regla para permitir tráfico.</td><td><code>sudo iptables -A INPUT -p tcp --dport 22 -j ACCEPT</code></td></tr><tr><td><code>iptables -D INPUT</code></td><td>Elimina una regla.</td><td><code>sudo iptables -D INPUT 1</code></td></tr><tr><td><code>iptables-save</code></td><td>Exporta reglas actuales.</td><td><code>sudo iptables-save &gt; backup.rules</code></td></tr><tr><td><code>nft list ruleset</code></td><td>Lista reglas de <strong>nftables</strong>.</td><td><code>sudo nft list ruleset</code></td></tr><tr><td><code>ufw status</code></td><td>Estado del firewall simplificado (<strong>UFW</strong>).</td><td><code>sudo ufw status</code></td></tr><tr><td><code>ufw allow</code></td><td>Permite tráfico en un puerto específico.</td><td><code>sudo ufw allow 443/tcp</code></td></tr></tbody></table><hr><h2 id="_5-pruebas-y-simulacion-de-trafico" tabindex="-1">5. <strong>Pruebas y simulación de tráfico</strong> <a class="header-anchor" href="#_5-pruebas-y-simulacion-de-trafico" aria-label="Permalink to &quot;5. **Pruebas y simulación de tráfico**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>iperf3 -s</code></td><td>Inicia un servidor de prueba de velocidad.</td><td><code>iperf3 -s</code></td></tr><tr><td><code>iperf3 -c</code></td><td>Cliente para probar velocidad contra el servidor.</td><td><code>iperf3 -c 192.168.1.20</code></td></tr><tr><td><code>tc qdisc add</code></td><td>Simula latencia y pérdida de paquetes.</td><td><code>sudo tc qdisc add dev eth0 root netem delay 200ms loss 10%</code></td></tr><tr><td><code>tc qdisc del</code></td><td>Elimina configuración de simulación.</td><td><code>sudo tc qdisc del dev eth0 root</code></td></tr><tr><td><code>nload</code></td><td>Muestra tráfico entrante y saliente en tiempo real.</td><td><code>sudo nload</code></td></tr></tbody></table><hr><h2 id="_6-administracion-de-dns-y-resolucion-de-nombres" tabindex="-1">6. <strong>Administración de DNS y resolución de nombres</strong> <a class="header-anchor" href="#_6-administracion-de-dns-y-resolucion-de-nombres" aria-label="Permalink to &quot;6. **Administración de DNS y resolución de nombres**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>dig</code></td><td>Consulta detallada de registros DNS.</td><td><code>dig openai.com ANY</code></td></tr><tr><td><code>host</code></td><td>Consulta rápida DNS.</td><td><code>host openai.com</code></td></tr><tr><td><code>nslookup</code></td><td>Consulta clásica DNS.</td><td><code>nslookup 8.8.8.8</code></td></tr><tr><td><code>resolvectl</code></td><td>Muestra y configura servidores DNS.</td><td><code>resolvectl status</code></td></tr></tbody></table><hr><h2 id="_7-administracion-de-servicios-de-red" tabindex="-1">7. <strong>Administración de servicios de red</strong> <a class="header-anchor" href="#_7-administracion-de-servicios-de-red" aria-label="Permalink to &quot;7. **Administración de servicios de red**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>systemctl status</code></td><td>Verifica estado de un servicio.</td><td><code>systemctl status ssh</code></td></tr><tr><td><code>systemctl restart</code></td><td>Reinicia un servicio.</td><td><code>sudo systemctl restart networking</code></td></tr><tr><td><code>journalctl -u</code></td><td>Muestra logs de un servicio.</td><td><code>journalctl -u ssh</code></td></tr><tr><td><code>service</code> <em>(método clásico)</em></td><td>Alternativa a <code>systemctl</code>.</td><td><code>sudo service ssh restart</code></td></tr></tbody></table><hr><h2 id="_8-escaneo-y-auditoria-de-red" tabindex="-1">8. <strong>Escaneo y auditoría de red</strong> <a class="header-anchor" href="#_8-escaneo-y-auditoria-de-red" aria-label="Permalink to &quot;8. **Escaneo y auditoría de red**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>nmap -sP</code></td><td>Descubre dispositivos en la red.</td><td><code>nmap -sP 192.168.1.0/24</code></td></tr><tr><td><code>nmap -A</code></td><td>Escaneo avanzado de un host.</td><td><code>nmap -A 192.168.1.10</code></td></tr><tr><td><code>arp-scan</code></td><td>Escaneo rápido de IPs y MACs.</td><td><code>sudo arp-scan --interface=eth0 192.168.1.0/24</code></td></tr><tr><td><code>whois</code></td><td>Consulta información de dominios.</td><td><code>whois openai.com</code></td></tr></tbody></table><hr><h2 id="_9-automatizacion-y-scripts-de-red" tabindex="-1">9. <strong>Automatización y scripts de red</strong> <a class="header-anchor" href="#_9-automatizacion-y-scripts-de-red" aria-label="Permalink to &quot;9. **Automatización y scripts de red**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>watch</code></td><td>Ejecuta un comando repetidamente.</td><td><code>watch -n 2 ip a</code></td></tr><tr><td><code>cron</code></td><td>Programa tareas automáticas.</td><td><code>crontab -e</code></td></tr><tr><td><code>curl</code></td><td>Automatiza peticiones HTTP.</td><td><code>curl -I https://example.com</code></td></tr><tr><td><code>wget</code></td><td>Descarga archivos automáticamente.</td><td><code>wget -c archivo.iso</code></td></tr></tbody></table><hr><h2 id="_10-flujos-de-trabajo-practicos-⚡" tabindex="-1">10. <strong>Flujos de trabajo prácticos</strong> ⚡ <a class="header-anchor" href="#_10-flujos-de-trabajo-practicos-⚡" aria-label="Permalink to &quot;10. **Flujos de trabajo prácticos** ⚡&quot;">​</a></h2><h3 id="🔹-verificar-conectividad-y-puertos-abiertos" tabindex="-1">🔹 <strong>Verificar conectividad y puertos abiertos</strong> <a class="header-anchor" href="#🔹-verificar-conectividad-y-puertos-abiertos" aria-label="Permalink to &quot;🔹 **Verificar conectividad y puertos abiertos**&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.8.8.8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tulnp</span></span></code></pre></div><h3 id="🔹-capturar-trafico-http-en-la-interfaz-eth0" tabindex="-1">🔹 <strong>Capturar tráfico HTTP en la interfaz eth0</strong> <a class="header-anchor" href="#🔹-capturar-trafico-http-en-la-interfaz-eth0" aria-label="Permalink to &quot;🔹 **Capturar tráfico HTTP en la interfaz eth0**&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcpdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vv</span></span></code></pre></div><h3 id="🔹-escanear-red-local-y-mostrar-dispositivos-conectados" tabindex="-1">🔹 <strong>Escanear red local y mostrar dispositivos conectados</strong> <a class="header-anchor" href="#🔹-escanear-red-local-y-mostrar-dispositivos-conectados" aria-label="Permalink to &quot;🔹 **Escanear red local y mostrar dispositivos conectados**&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.1.0/24</span></span></code></pre></div><h3 id="🔹-medir-ancho-de-banda-entre-dos-servidores" tabindex="-1">🔹 <strong>Medir ancho de banda entre dos servidores</strong> <a class="header-anchor" href="#🔹-medir-ancho-de-banda-entre-dos-servidores" aria-label="Permalink to &quot;🔹 **Medir ancho de banda entre dos servidores**&quot;">​</a></h3><p>En <strong>servidor</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iperf3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span></span></code></pre></div><p>En <strong>cliente</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iperf3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.1.20</span></span></code></pre></div>',40)])])}const g=d(s,[["render",r]]);export{u as __pageData,g as default};
